create extension if not exists pgcrypto;
create table if not exists profiles(id uuid primary key default gen_random_uuid(),discord_id text unique not null,username text not null,discord_username text,email text,avatar_url text,banner_url text,accent_color bigint,role text not null default 'Пользователь',is_founder boolean not null default false,is_banned boolean not null default false,xp integer not null default 0,questions_count integer not null default 0,ai_tokens_used integer not null default 0,helpful_answers integer not null default 0,registered_at timestamptz not null default now(),last_login_at timestamptz,updated_at timestamptz not null default now());
create table if not exists ai_history(id uuid primary key default gen_random_uuid(),discord_id text not null references profiles(discord_id) on delete cascade,question text not null,answer text not null,created_at timestamptz not null default now());
create table if not exists favorites(id uuid primary key default gen_random_uuid(),discord_id text not null references profiles(discord_id) on delete cascade,title text not null,content text not null,source text not null default 'AI',created_at timestamptz not null default now());
create table if not exists user_settings(discord_id text primary key references profiles(discord_id) on delete cascade,animations boolean not null default true,compact_answers boolean not null default false,confirm_clear boolean not null default true,updated_at timestamptz not null default now());
create table if not exists news(id uuid primary key default gen_random_uuid(),title text not null,content text not null,published boolean not null default true,created_by text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists rules(id uuid primary key default gen_random_uuid(),title text not null,category text not null default 'Общие правила',content text not null,published boolean not null default true,created_by text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists knowledge_base(id uuid primary key default gen_random_uuid(),title text not null,content text not null,tags text[] not null default '{}',published boolean not null default true,created_by text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create or replace function increment_profile_activity(p_discord_id text,p_xp integer,p_questions integer,p_tokens integer) returns void language plpgsql security definer as $$begin update profiles set xp=xp+p_xp,questions_count=questions_count+p_questions,ai_tokens_used=ai_tokens_used+p_tokens,updated_at=now() where discord_id=p_discord_id;end;$$;
alter table profiles enable row level security;alter table ai_history enable row level security;alter table favorites enable row level security;alter table user_settings enable row level security;alter table news enable row level security;alter table rules enable row level security;alter table knowledge_base enable row level security;